const { ethers } = require("ethers");

function assertEnv(name) {
  if (!process.env[name] || String(process.env[name]).trim() === "") {
    throw new Error(`Missing required env var: ${name}`);
  }
}

function normalizePrivateKey(pk) {
  if (!pk) throw new Error("Private key is required");
  let v = String(pk).trim();
  if (!v.startsWith("0x")) v = "0x" + v;
  if (!/^0x[0-9a-fA-F]{64}$/.test(v)) throw new Error("Invalid private key format");
  return v;
}

function parsePrivateKeys(input) {
  if (!input) return [];
  if (Array.isArray(input)) return input.map(normalizePrivateKey);
  return String(input)
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean)
    .map(normalizePrivateKey);
}

class Web3BackendService {
  constructor(options = {}) {
    const rpcUrl = options.rpcUrl || process.env.RPC_URL;
    if (!rpcUrl) throw new Error("RPC URL is required (options.rpcUrl or RPC_URL env var)");

    this.provider = options.provider || new ethers.JsonRpcProvider(rpcUrl);

    const pks = parsePrivateKeys(options.privateKeys || process.env.PRIVATE_KEYS || process.env.PRIVATE_KEY);
    if (pks.length === 0) throw new Error("At least one private key is required (options.privateKeys or PRIVATE_KEYS/PRIVATE_KEY env var)");

    this.wallets = pks.map((pk) => new ethers.Wallet(pk, this.provider));
    this.defaultWalletIndex = Number.isInteger(options.defaultWalletIndex) ? options.defaultWalletIndex : 0;

    this.chainIdPromise = null;
  }

  getWallet(index = this.defaultWalletIndex) {
    if (index < 0 || index >= this.wallets.length) throw new Error("Wallet index out of range");
    return this.wallets[index];
  }

  async getChainId() {
    if (!this.chainIdPromise) {
      this.chainIdPromise = this.provider.getNetwork().then((n) => Number(n.chainId));
    }
    return this.chainIdPromise;
  }

  async getAddress(index) {
    return this.getWallet(index).getAddress();
  }

  async getBalance(addressOrIndex) {
    const address = typeof addressOrIndex === "number" ? await this.getAddress(addressOrIndex) : addressOrIndex;
    return this.provider.getBalance(address);
  }

  async getNonce(index, blockTag = "pending") {
    const wallet = this.getWallet(index);
    return this.provider.getTransactionCount(wallet.address, blockTag);
  }

  async estimateGasForEthTransfer(fromIndex, to, amountEth, overrides = {}) {
    const wallet = this.getWallet(fromIndex);
    const value = ethers.parseEther(String(amountEth));
    const tx = { to, value, ...overrides };
    return wallet.estimateGas(tx);
  }

  async sendEth(fromIndex, to, amountEth, txOverrides = {}) {
    if (!ethers.isAddress(to)) throw new Error("Invalid recipient address");
    const wallet = this.getWallet(fromIndex);
    const value = ethers.parseEther(String(amountEth));

    const feeData = await this.provider.getFeeData();
    const tx = {
      to,
      value,
      ...txOverrides,
    };

    if (tx.gasLimit == null) {
      tx.gasLimit = await wallet.estimateGas(tx);
    }

    if (tx.maxFeePerGas == null && tx.maxPriorityFeePerGas == null) {
      if (feeData.maxFeePerGas != null && feeData.maxPriorityFeePerGas != null) {
        tx.maxFeePerGas = feeData.maxFeePerGas;
        tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
      } else if (feeData.gasPrice != null) {
        tx.gasPrice = feeData.gasPrice;
      }
    }

    const response = await wallet.sendTransaction(tx);
    return response;
  }

  async waitForTx(txHashOrResponse, confirmations = 1, timeoutMs) {
    const hash = typeof txHashOrResponse === "string" ? txHashOrResponse : txHashOrResponse.hash;
    return this.provider.waitForTransaction(hash, confirmations, timeoutMs);
  }

  getContract(address, abi, signerOrIndex) {
    if (!ethers.isAddress(address)) throw new Error("Invalid contract address");
    let runner = this.provider;
    if (typeof signerOrIndex === "number") runner = this.getWallet(signerOrIndex);
    else if (signerOrIndex && typeof signerOrIndex === "object") runner = signerOrIndex;
    return new ethers.Contract(address, abi, runner);
  }

  async callContract(address, abi, method, args = [], callOverrides = {}) {
    const contract = this.getContract(address, abi, null);
    if (typeof contract[method] !== "function") throw new Error(`Method not found on contract: ${method}`);
    return contract[method](...args, callOverrides);
  }

  async sendContractTx(fromIndex, address, abi, method, args = [], txOverrides = {}) {
    const contract = this.getContract(address, abi, fromIndex);
    if (typeof contract[method] !== "function") throw new Error(`Method not found on contract: ${method}`);

    const feeData = await this.provider.getFeeData();

    const populated = await contract[method].populateTransaction(...args, txOverrides);

    if (populated.gasLimit == null) {
      populated.gasLimit = await contract.runner.estimateGas(populated);
    }

    if (populated.maxFeePerGas == null && populated.maxPriorityFeePerGas == null && populated.gasPrice == null) {
      if (feeData.maxFeePerGas != null && feeData.maxPriorityFeePerGas != null) {
        populated.maxFeePerGas = feeData.maxFeePerGas;
        populated.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
      } else if (feeData.gasPrice != null) {
        populated.gasPrice = feeData.gasPrice;
      }
    }

    const response = await contract.runner.sendTransaction(populated);
    return response;
  }

  async signMessage(fromIndex, message) {
    const wallet = this.getWallet(fromIndex);
    return wallet.signMessage(message);
  }

  async signTypedData(fromIndex, domain, types, value) {
    const wallet = this.getWallet(fromIndex);
    return wallet.signTypedData(domain, types, value);
  }

  async getTxReceipt(txHash) {
    return this.provider.getTransactionReceipt(txHash);
  }

  async getTx(txHash) {
    return this.provider.getTransaction(txHash);
  }
}

